/**
 * PopupDialog Web Component
 * A draggable popup dialog that can be used in any web application
 */
declare class PopupDialog extends HTMLElement {
    /**
     * Creates an instance of PopupDialog
     */
    constructor();

    /**
     * Observed attributes that trigger attributeChangedCallback
     */
    static get observedAttributes(): string[];

    /**
     * Called when an observed attribute changes
     */
    attributeChangedCallback(name: string, oldValue: string | null, newValue: string | null): void;

    /**
     * Called when the element is connected to the DOM
     */
    connectedCallback(): void;

    /**
     * Renders the shadow DOM content
     */
    render(): void;

    /**
     * Sets up event listeners for the component
     */
    setupEventListeners(): void;

    /**
     * Starts the dragging operation
     */
    startDragging(e: MouseEvent): void;

    /**
     * Handles the drag move event
     */
    dragMove(e: MouseEvent): void;

    /**
     * Ends the dragging operation
     */
    dragEnd(): void;

    /**
     * Updates the draggable state of the dialog
     */
    updateDraggable(isDraggable: boolean): void;

    /**
     * Sets the title of the dialog
     */
    setTitle(title: string): void;

    /**
     * Sets the position of the dialog
     */
    setPosition(left: number, top: number): void;

    /**
     * Sets the size of the dialog
     */
    setSize(width: number, height: number): void;

    /**
     * Opens the dialog
     */
    open(event?: Event): void;

    /**
     * Closes the dialog
     */
    close(event?: Event): void;
}

export default PopupDialog;
